import { styled } from 'styled-components';

import Carousel, { Group as CarouselGroup } from '#components/Carousel';
import { Icon } from '#components/Icon';

import * as device from '#theme/devices';

import { hex2rgba } from '#utils/colors';

export const Wrapper = styled.div`
  --carousel-padding: ${({ theme }) =>
    theme.spacing.x1_5}px; /* padding around the grey bg */
  --slide-gap: var(--carousel-padding); /* gap between the slides */
  --item-padding-x: calc(var(--slide-gap) / 2);
  position: relative;
  background-color: ${({ theme }) => theme.color.canvas.secondary};

  @media ${device.laptop} {
    --carousel-padding: ${({ theme }) => theme.spacing.x3}px;
  }
`;

export const StyledCarousel = styled(Carousel)`
  /*
    We need to adjust the first and last items in the carousel to account for
    the space around them
  */
  ${CarouselGroup} {
    --group-padding-x: calc(var(--carousel-padding) - var(--item-padding-x));

    &:first-child {
      padding-left: var(--group-padding-x);
    }

    &:last-child {
      padding-right: var(--group-padding-x);
    }
  }
`;

export const Title = styled.h3`
  padding: var(--carousel-padding) var(--carousel-padding) 0;
  margin: 0;
  ${({ theme }) => theme.textStyle.tag.small.expanded}

  @media ${device.tablet} {
    ${({ theme }) => theme.textStyle.tag.base.expanded}
  }

  @media ${device.laptop} {
    --title-padding-top: ${({ theme }) => theme.spacing.x2}px;

    ${({ theme }) => theme.textStyle.tag.large.expanded}
  }
`;

export const Item = styled.div`
  --item-padding-top: ${({ theme }) => theme.spacing.x1}px;
  --item-padding-x: calc(var(--slide-gap) / 2);
  display: flex;
  width: auto;
  flex: 0 0 auto;
  padding: var(--item-padding-top) var(--item-padding-x);
  scroll-snap-align: start;

  @media ${device.laptop} {
    --item-padding-top: 16px;
  }
`;

const Button = styled.button`
  --height: 60px;
  --width: 60px;
  --pos-x: ${({ theme }) => theme.spacing.x1}px;
  display: flex;
  position: absolute;
  top: calc(50% - (var(--width) / 2));
  width: var(--width);
  height: var(--width);
  align-items: center;
  justify-content: center;
  border-radius: 50%;
  background-color: ${({ theme }) => hex2rgba(theme.color.ink.muted, 0.3)};
  color: ${({ theme }) => theme.color.ink.base};
  pointer-events: auto;
  transition: background-color ${({ theme }) => theme.transition.base},
    opacity ${({ theme }) => theme.transition.base};

  &:hover,
  &:active {
    background-color: ${({ theme }) => hex2rgba(theme.color.ink.muted, 0.5)};
  }

  &[disabled] {
    opacity: 0;
  }
`;

export const PrevButton = styled(Button)`
  left: var(--pos-x);
`;

export const NextButton = styled(Button)`
  right: var(--pos-x);
`;

export const ButtonIcon = styled(Icon).attrs({
  size: 'large',
})``;

const Fade = styled.div`
  --opaque: ${({ theme }) => theme.color.canvas.secondary};
  --transparent: ${({ theme }) => hex2rgba(theme.color.canvas.secondary, 0)};
  --gradient: linear-gradient(90deg, var(--fade-from), var(--fade-to));
  --z-fade: 0;
  --z-btn: 1;
  position: absolute;
  top: 0;
  bottom: 0;

  &::before {
    display: block;
    position: absolute;
    top: 0;
    bottom: 0;
    z-index: var(--z-fade);
    width: 174px;
    height: 100%;
    background-image: var(--gradient);
    content: '';
    opacity: ${({ $disabled }) => ($disabled ? 0 : 1)};
    pointer-events: none;
  }

  ${Button} {
    z-index: var(--z-btn);
  }
`;

export const FadeLeft = styled(Fade)`
  --fade-from: var(--opaque);
  --fade-to: var(--transparent);
  left: 0;

  &::before {
    left: 0;
  }
`;

export const FadeRight = styled(Fade)`
  --fade-from: var(--transparent);
  --fade-to: var(--opaque);
  right: 0;

  &::before {
    right: 0;
  }
`;
