import PropTypes from 'prop-types';

import productCarouselCardPropTypes from './ProductCarouselCard.types';

export default {
  ...productCarouselCardPropTypes,
  /** The endpoint from which to retrieve the dynamic price */
  endpoint: PropTypes.string.isRequired,
  /** Whether the product is currently loading i.e. when async fetching a price */
  isLoading: PropTypes.bool,
  /** Whether the product is currently visible within the carousel viewport */
  isVisible: PropTypes.bool,
  /** A callback with which to transform the fetch response for the component */
  responseTransformer: PropTypes.func,
};
