import { useState, useEffect } from 'react';

import propTypes from './LazyProductCarouselCard.types';
import ProductCarouselCard from './ProductCarouselCard';

import { useFetch, Step } from '#hooks/useFetch';

/**
 * LazyProductCarouselCard component that fetches data from an endpoint and renders a ProductCarouselCard.
 *
 * @param {Object} props - Component props.
 * @param {string} props.endpoint - The endpoint to fetch data from.
 * @param {string} props.prettyPrice - The pretty price to display.
 * @param {boolean} [props.isVisible=false] - Whether the component is visible or not.
 * @returns {JSX.Element} - The rendered component.
 */
export const LazyProductCarouselCard = (props) => {
  const {
    endpoint,
    vendorLink,
    prettyPrice,
    responseTransformer,
    isVisible = false,
  } = props;
  const [isLoaded, setIsLoaded] = useState(false);

  const initialData = { link: vendorLink, price: prettyPrice };

  const { step, data, error } = useFetch({
    url: endpoint,
    initialData,
    triggerFetch: isVisible && !isLoaded,
    responseTransformer,
  });

  useEffect(() => {
    (step === Step.ERROR || step === Step.SUCCESS) && setIsLoaded(true);
  }, [step]);

  const isLoading = step === Step.INITIAL || step === Step.LOADING;
  const hasError = step === Step.ERROR;
  const hasNoData = step === Step.SUCCESS && !data;

  if (isLoading) {
    return <ProductCarouselCard {...props} isLoading={true} />;
  }

  if (hasError || hasNoData) {
    error && console.warn(error);

    return (
      <ProductCarouselCard
        {...props}
        prettyPrice={prettyPrice}
        isStaticPrice={true}
      />
    );
  }

  const { price, link } = data;

  return (
    <ProductCarouselCard {...props} prettyPrice={price} vendorLink={link} />
  );
};

LazyProductCarouselCard.propTypes = propTypes;

export default LazyProductCarouselCard;
