import { LazyProductCarouselCard } from '#components/ProductCarouselCard';

import {
  Wrapper,
  StyledCarousel,
  Title,
  NextButton,
  PrevButton,
  ButtonIcon,
  FadeRight,
  FadeLeft,
} from './ProductCarousel.styles';
import propTypes, { buttonPropTypes } from './ProductCarousel.types';
import ProductCarouselSlide from './ProductCarouselSlide';

import ChevronLeftSVG from '#icons/chevron-left-solid-24.svg';
import ChevronRightSVG from '#icons/chevron-right-solid-24.svg';

const ButtonPrev = ({ disabled, onClick, ...props }) => (
  <FadeLeft $disabled={disabled}>
    <PrevButton {...props} disabled={disabled} onClick={onClick}>
      <ButtonIcon svg={ChevronLeftSVG} />
    </PrevButton>
  </FadeLeft>
);
ButtonPrev.propTypes = buttonPropTypes;

const ButtonNext = ({ disabled, onClick, ...props }) => (
  <FadeRight $disabled={disabled}>
    <NextButton {...props} disabled={disabled} onClick={onClick}>
      <ButtonIcon svg={ChevronRightSVG} />
    </NextButton>
  </FadeRight>
);
ButtonNext.propTypes = buttonPropTypes;

const ProductCarousel = ({
  items,
  title,
  initialIndex = 0,
  responseTransformer,
  ...props
}) => (
  <Wrapper {...props}>
    {title && <Title>{title}</Title>}
    <StyledCarousel
      initialIndex={initialIndex}
      ButtonPrev={ButtonPrev}
      ButtonNext={ButtonNext}
      increment={2}
      items={items}
      renderSlide={({ slideIndex, item, isVisible, ref }) => (
        <ProductCarouselSlide
          key={`item-${slideIndex}`}
          isFirst={slideIndex === 0}
          isLast={slideIndex === items.length - 1}
          ref={ref}
        >
          <LazyProductCarouselCard
            {...item}
            isVisible={isVisible}
            responseTransformer={responseTransformer}
          />
        </ProductCarouselSlide>
      )}
    />
  </Wrapper>
);

ProductCarousel.propTypes = propTypes;

export default ProductCarousel;
