import { forwardRef } from 'react';

import { Item } from './ProductCarousel.styles';
import { slidePropTypes } from './ProductCarousel.types';

const ProductCarouselSlide = forwardRef(function ProductCarouselSlide(
  { children },
  ref,
) {
  return <Item ref={ref}>{children}</Item>;
});

ProductCarouselSlide.propTypes = slidePropTypes;

export default ProductCarouselSlide;
